#include<bits/stdc++.h>
using namespace std;
bool flag[210][210][210],dp[210][210][210];
map<char,int> id;
char s[210];
int main()
{
    id['W']=1;
    id['I']=2;
    id['N']=3;
    id['G']=4;
    int w,I,n,g;
    scanf("%d%d%d%d",&w,&I,&n,&g);
    for(int i=1;i<=w;i++)
    {
        char a,b;
        cin>>a>>b;
        flag[1][id[a]][id[b]]=1;
    }
    for(int i=1;i<=I;i++)
    {
        char a,b;
        cin>>a>>b;
        flag[2][id[a]][id[b]]=1;
    }
    for(int i=1;i<=n;i++)
    {
        char a,b;
        cin>>a>>b;
        flag[3][id[a]][id[b]]=1;
    }
    for(int i=1;i<=g;i++)
    {
        char a,b;
        cin>>a>>b;
        flag[4][id[a]][id[b]]=1;
    }
    scanf("%s",s+1);
    int m=strlen(s+1);
    for(int i=1;i<=m;i++)
    {
        dp[i][i][id[s[i]]]=1;
    }
    for(int len=2;len<=m;len++)
    {
        for(int l=1,r=len;r<=m;l++,r++)
        {
            for(int k=l;k<r;k++)
            {
                for(int a=1;a<=4;a++)
                {
                    for(int b=1;b<=4;b++)
                    {
                        for(int c=1;c<=4;c++)
                        {
                            dp[l][r][a]|=flag[a][b][c]&dp[l][k][b]&dp[k+1][r][c];
                        }
                    }
                }
            }
        }
    }
    int f=0;
    if(dp[1][m][1])
    {
        printf("W");
        f=1;
    }
    if(dp[1][m][2])
    {
        printf("I");
        f=1;
    }
    if(dp[1][m][3])
    {
        printf("N");
        f=1;
    }
    if(dp[1][m][4])
    {
        printf("G");
        f=1;
    }
    if(f==0)
    {
        printf("The name is wrong!");
    }
    return 0;
}
